mapper.select:
SELECT A.ID, B.SHIP_NAME, A.SHIPVOYAGE_ID, A.SHIPVOYAGE_ITEM_ID, A.VOYAGE, A.LOAD_UNLOAD, A.DYNAMIC_TYPE_CODE, A.DYNAMIC_TYPE_NAME, A.DYNAMIC_START_TIME, A.DYNAMIC_END_TIME, A.BERTH_ID, A.BERTH_NAME, A.BOLLARD_NO_START, A.BOLLARD_NO_END, A.BERTH_TYPE, A.STOP_TYPE_CODE, A.STOP_TYPE_NAME, A.STOP_ID, A.STOP_NAME, A.REMARK, A.STOP_TIME_LEN, A.CREATE_BY, A.CREATE_BY_NAME, A.CREATE_TIME, A.UPDATE_BY, A.UPDATE_BY_NAME, A.UPDATE_TIME FROM T_DIS_SHIP_DYNAMIC A LEFT JOIN T_DIS_SHIPVOYAGE B ON A.SHIPVOYAGE_ID = B.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM C ON A.SHIPVOYAGE_ITEM_ID = C.ID
A.SHIPVOYAGE_ID = #{shipvoyageId}
ORDER BY A.DYNAMIC_START_TIME

SELECT A.ID, B.SHIP_NAME, A.SHIPVOYAGE_ID, A.SHIPVOYAGE_ITEM_ID, A.VOYAGE, A.LOAD_UNLOAD, A.DYNAMIC_TYPE_CODE, A.DYNAMIC_TYPE_NAME, A.DYNAMIC_START_TIME, A.DYNAMIC_END_TIME, A.BERTH_ID, A.BERTH_NAME, A.BOLLARD_NO_START, A.BOLLARD_NO_END, A.BERTH_TYPE, A.STOP_TYPE_CODE, A.STOP_TYPE_NAME, A.STOP_ID, A.STOP_NAME, A.REMARK, A.STOP_TIME_LEN, A.CREATE_BY, A.CREATE_BY_NAME, A.CREATE_TIME, A.UPDATE_BY, A.UPDATE_BY_NAME, A.UPDATE_TIME FROM T_DIS_SHIP_DYNAMIC A LEFT JOIN T_DIS_SHIPVOYAGE B ON A.SHIPVOYAGE_ID = B.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM C ON A.SHIPVOYAGE_ITEM_ID = C.ID
DYNAMIC_TYPE_CODE IN ('80','90') AND A.SHIPVOYAGE_ID = #{shipvoyageId}
AND C.IMP_EXP = #{impExp}
ORDER BY A.DYNAMIC_START_TIME,CREATE_TIME

SELECT TDS.ID TDS_ID, TDS.SCN TDS_SCN, TS.MMSI MMSI, TDS.SHIP_ID TDS_SHIP_ID, TDS.SHIP_NAME TDS_SHIP_NAME, TS.SHIP_NAME_EN TS_SHIP_NAME_EN, TS.NATION_CODE TS_NATION_CODE, TS.SHIP_LENGTH TS_SHIP_LENGTH, TS.SHIP_WIDTH TS_SHIP_WIDTH, TS.DWT TS_DWT, TS.TOTAL_WEIGHT TS_TOTAL_WEIGHT, TS.NET_WEIGHT TS_NET_WEIGHT, DC.DICT_LABEL DC_DICT_LABEL, TDS.IMP_EXP TDS_IMP_EXP, TDS.TRADE_TYPE TDS_TRADE_TYPE, TDS.LOAD_UNLOAD TDS_LOAD_UNLOAD, TDS.IS_WATER TDS_IS_WATER, TDS.IS_SHORE_POWER TDS_IS_SHORE_POWER, TDS.REQ_WATER TDS_REQ_WATER, TDS.REQ_ELECTRICITY TDS_REQ_ELECTRICITY, TDS.BOW_DRAFT TDS_BOW_DRAFT, TDS.STERN_DRAFT TDS_STERN_DRAFT, TDS.IS_TUG TDS_IS_TUG, TDS.TUG_NUMBER TDS_TUG_NUMBER, TDS.PILOTAGE TDS_PILOTAGE, TDS.IS_PAYMENT TDS_IS_PAYMENT, TDS.PAYMENT_AMOUNT TDS_PAYMENT_AMOUNT, TDS.IS_DANGEROUS TDS_IS_DANGEROUS, TDS.ARRIVAL_TIME_PLAN TDS_ARRIVAL_TIME_PLAN, TDS.LEAVE_PORT_TIME_PLAN TDS_LEAVE_PORT_TIME_PLAN, TDS.LEAVE_PORT_TIME TDS_LEAVE_PORT_TIME, TDS.ARRIVAL_ANCHORAGE_TIME TDS_ARRIVAL_ANCHORAGE_TIME, TDS.LEAVE_ANCHORAGE_TIME TDS_LEAVE_ANCHORAGE_TIME, TDS.BERTH_TIME TDS_BERTH_TIME, TDS.BERTH_ID TDS_BERTH_ID, TDS.BERTH_NAME TDS_BERTH_NO, TDS.BERTH_TYPE TDS_BERTH_TYPE, TDS.BOLLARD_NO_START TDS_BOLLARD_NO_START, TDS.BOLLARD_NO_END TDS_BOLLARD_NO_END, TDS.LEAVE_BERTH_TIME TDS_LEAVE_BERTH_TIME, TDS.RECEIVE_BY TDS_RECEIVE_BY, TDS.RECEIVE_BY_NAME TDS_RECEIVE_BY_NAME, TDS.RECEIVE_TIME TDS_RECEIVE_TIME, TDS.DEL_FLAG TDS_DEL_FLAG, TDS.DEL_REMARK TDS_DEL_REMARK, TDS.DEL_BY TDS_DEL_BY, TDS.DEL_BY_NAME TDS_DEL_BY_NAME, TDS.DEL_TIME TDS_DEL_TIME, TDS.REMARK TDS_REMARK, TDS.CREATE_BY TDS_CREATE_BY, TDS.CREATE_BY_NAME TDS_CREATE_BY_NAME, TDS.CREATE_TIME TDS_CREATE_TIME, TDS.UPDATE_BY TDS_UPDATE_BY, TDS.UPDATE_BY_NAME TDS_UPDATE_BY_NAME, TDS.UPDATE_TIME TDS_UPDATE_TIME, TDS.START_PORT_ID TDS_START_PORT_ID, TDS.START_PORT_NAME TDS_START_PORT_NAME, TDS.END_PORT_ID TDS_END_PORT_ID, TDS.END_PORT_NAME TDS_END_PORT_NAME, TDS.PRE_PORT_ID TDS_PRE_PORT_ID, TDS.PRE_PORT_NAME TDS_PRE_PORT_NAME, TDS.NEXT_PORT_ID TDS_NEXT_PORT_ID, TDS.NEXT_PORT_NAME TDS_NEXT_PORT_NAME, TDS.SHIP_STATUS_CODE TDS_SHIP_STATUS_CODE, TDS.SHIP_STATUS_NAME TDS_SHIP_STATUS_NAME, TDS.CERTIFICATE_PATH TDS_CERTIFICATE_PATH, TDS.IS_START_WORK TDS_IS_START_WORK, TDS.IS_LAST_ARRIVAL_TYPE TDS_IS_LAST_ARRIVAL_TYPE, TDS.BERTHING_CHARGE TDS_BERTHING_CHARGE, TDS.JIESHOU_REMARK TDS_JIESHOU_REMARK, TS.CAPTAIN_PHONE TS_CAPTAIN_PHONE, TDS.WHARF TDS_WHARF, TS.HATCH_NUM SHIP_HATCH_NUM, TDS.CONFIRM_TIME TDS_CONFIRM_TIME, "IN".ID IN_ID, "IN".SHIPVOYAGE_ID IN_SHIPVOYAGE_ID, "IN".IMP_EXP IN_IMP_EXP, "IN".TRADE_TYPE IN_TRADE_TYPE, "IN".LOAD_UNLOAD IN_LOAD_UNLOAD, "IN".VOYAGE IN_VOYAGE, "IN".COMPANY_ID IN_COMPANY_ID, "IN".COMPANY_NAME IN_COMPANY_NAME, "IN".CARGO_CATEGORY_CODE IN_CARGO_CATEGORY_CODE, "IN".CARGO_CATEGORY_NAME IN_CARGO_CATEGORY_NAME, "IN".CARGO_NUM IN_CARGO_NUM, "IN".CUSTOMER_ID IN_CUSTOMER_ID, "IN".CUSTOMER_NAME IN_CUSTOMER_NAME, "IN".CONTACTS IN_CONTACTS, "IN".SHIP_PHONE IN_SHIP_PHONE, "IN".PAYMENT_AMOUNT IN_PAYMENT_AMOUNT, "IN".REMARK IN_REMARK, "IN".CREATE_BY IN_CREATE_BY, "IN".CREATE_BY_NAME IN_CREATE_BY_NAME, "IN".CREATE_TIME IN_CREATE_TIME, "IN".UPDATE_BY IN_UPDATE_BY, "IN".UPDATE_BY_NAME IN_UPDATE_BY_NAME, "IN".UPDATE_TIME IN_UPDATE_TIME, "IN".SHIP_STATUS_CODE IN_SHIP_STATUS_CODE, "IN".SHIP_STATUS_NAME IN_SHIP_STATUS_NAME, "IN".WORK_START_TIME IN_WORK_START_TIME, "IN".WORK_END_TIME IN_WORK_END_TIME, "IN".PRE_CHANGE_SHIP_NAME IN_PRE_CHANGE_SHIP_NAME, "IN".PRE_CHANGE_SHIP_NO IN_PRE_CHANGE_SHIP_NO, "OUT".ID OUT_ID, "OUT".SHIPVOYAGE_ID OUT_SHIPVOYAGE_ID, "OUT".IMP_EXP OUT_IMP_EXP, "OUT".TRADE_TYPE OUT_TRADE_TYPE, "OUT".LOAD_UNLOAD OUT_LOAD_UNLOAD, "OUT".VOYAGE OUT_VOYAGE, "OUT".COMPANY_ID OUT_COMPANY_ID, "OUT".COMPANY_NAME OUT_COMPANY_NAME, "OUT".CARGO_CATEGORY_CODE OUT_CARGO_CATEGORY_CODE, "OUT".CARGO_CATEGORY_NAME OUT_CARGO_CATEGORY_NAME, "OUT".CARGO_NUM OUT_CARGO_NUM, "OUT".CUSTOMER_ID OUT_CUSTOMER_ID, "OUT".CUSTOMER_NAME OUT_CUSTOMER_NAME, "OUT".CONTACTS OUT_CONTACTS, "OUT".SHIP_PHONE OUT_SHIP_PHONE, "OUT".PAYMENT_AMOUNT OUT_PAYMENT_AMOUNT, "OUT".REMARK OUT_REMARK, "OUT".CREATE_BY OUT_CREATE_BY, "OUT".CREATE_BY_NAME OUT_CREATE_BY_NAME, "OUT".CREATE_TIME OUT_CREATE_TIME, "OUT".UPDATE_BY OUT_UPDATE_BY, "OUT".UPDATE_BY_NAME OUT_UPDATE_BY_NAME, "OUT".UPDATE_TIME OUT_UPDATE_TIME, "OUT".SHIP_STATUS_CODE OUT_SHIP_STATUS_CODE, "OUT".SHIP_STATUS_NAME OUT_SHIP_STATUS_NAME, "OUT".WORK_START_TIME OUT_WORK_START_TIME, "OUT".WORK_END_TIME OUT_WORK_END_TIME FROM T_DIS_SHIPVOYAGE TDS LEFT JOIN T_DIS_SHIPVOYAGE_ITEM "IN" ON ("IN".IMP_EXP = 'IN' AND TDS.ID = "IN".SHIPVOYAGE_ID) LEFT JOIN T_DIS_SHIPVOYAGE_ITEM "OUT" ON ("OUT".IMP_EXP = 'OUT' AND TDS.ID = "OUT".SHIPVOYAGE_ID) LEFT JOIN M_SHIP TS ON TS.ID = TDS.SHIP_ID LEFT JOIN M_DICT_DATA DC ON DC.DICT_VALUE = TS.SHIP_KIND_CODE AND DC.DICT_TYPE = 'SHIP_KIND'
TDS.SHIP_STATUS_CODE IN ('00', '11', '10', '20','30','50','60', '70','80','90','100','110')
AND TS.SHIP_KIND_CODE = #{shipKindCode,jdbcType=VARCHAR}
and TDS.ID = #{id, jdbcType=BIGINT}
and TDS.SCN = #{scn, jdbcType=VARCHAR}
and TDS.SHIP_ID = #{shipId, jdbcType=BIGINT}
AND (TDS.SHIP_NAME LIKE #{shipName,jdbcType=VARCHAR})
AND ("IN".VOYAGE LIKE #{voyage,jdbcType=VARCHAR} OR "OUT".VOYAGE LIKE #{voyage,jdbcType=VARCHAR})
and TDS.IMP_EXP = #{impExp, jdbcType=VARCHAR}
and TDS.TRADE_TYPE = #{tradeType, jdbcType=VARCHAR}
and TDS.LOAD_UNLOAD = #{loadUnload, jdbcType=VARCHAR}
and TDS.IS_WATER = #{isWater, jdbcType=VARCHAR}
and TDS.IS_SHORE_POWER = #{isShorePower, jdbcType=VARCHAR}
and TDS.REQ_WATER = #{reqWater, jdbcType=VARCHAR}
and TDS.REQ_ELECTRICITY = #{reqElectricity, jdbcType=VARCHAR}
and TDS.BOW_DRAFT = #{bowDraft, jdbcType=VARCHAR}
and TDS.STERN_DRAFT = #{sternDraft, jdbcType=VARCHAR}
and TDS.IS_TUG = #{isTug, jdbcType=VARCHAR}
and TDS.TUG_NUMBER = #{tugNumber, jdbcType=INTEGER}
and TDS.PILOTAGE = #{pilotage, jdbcType=VARCHAR}
and TDS.IS_PAYMENT = #{isPayment, jdbcType=VARCHAR}
and TDS.PAYMENT_AMOUNT = #{paymentAmount, jdbcType=VARCHAR}
and TDS.IS_DANGEROUS = #{isDangerous, jdbcType=VARCHAR}
and TDS.ARRIVAL_TIME_PLAN = #{arrivalTimePlan, jdbcType=TIMESTAMP}
and TDS.LEAVE_PORT_TIME_PLAN = #{leavePortTimePlan, jdbcType=TIMESTAMP}
AND TDS.LEAVE_PORT_TIME >= #{startLeaveTime, jdbcType=VARCHAR}
AND #{endLeaveTime, jdbcType=VARCHAR} >= TDS.LEAVE_PORT_TIME
and TDS.ARRIVAL_ANCHORAGE_TIME = #{arrivalAnchorageTime, jdbcType=TIMESTAMP}
and TDS.LEAVE_ANCHORAGE_TIME = #{leaveAnchorageTime, jdbcType=TIMESTAMP}
and TDS.BERTH_TIME = #{berthTime, jdbcType=TIMESTAMP}
and TDS.BERTH_ID = #{berthId, jdbcType=BIGINT}
and TDS.BERTH_NAME = #{berthName, jdbcType=VARCHAR}
and TDS.BERTH_TYPE = #{berthType, jdbcType=VARCHAR}
and TDS.BOLLARD_NO_START = #{bollardNoStart, jdbcType=VARCHAR}
and TDS.BOLLARD_NO_END = #{bollardNoEnd, jdbcType=VARCHAR}
and TDS.LEAVE_BERTH_TIME = #{leaveBerthTime, jdbcType=TIMESTAMP}
and TDS.RECEIVE_BY = #{receiveBy, jdbcType=BIGINT}
and TDS.RECEIVE_BY_NAME = #{receiveByName, jdbcType=VARCHAR}
and TDS.RECEIVE_TIME = #{receiveTime, jdbcType=TIMESTAMP}
and TDS.DEL_FLAG = #{delFlag,jdbcType=VARCHAR}
and TDS.DEL_REMARK = #{delRemark, jdbcType=VARCHAR}
and TDS.DEL_BY = #{delBy, jdbcType=BIGINT}
and TDS.DEL_BY_NAME = #{delByName, jdbcType=VARCHAR}
and TDS.DEL_TIME = #{delTime, jdbcType=TIMESTAMP}
and TDS.REMARK = #{remark, jdbcType=VARCHAR}
and TDS.CREATE_BY = #{createBy, jdbcType=BIGINT}
and TDS.CREATE_BY_NAME = #{createByName, jdbcType=VARCHAR}
and TDS.CREATE_TIME = #{createTime, jdbcType=TIMESTAMP}
and TDS.UPDATE_BY = #{updateBy, jdbcType=BIGINT}
and TDS.UPDATE_BY_NAME = #{updateByName, jdbcType=VARCHAR}
and TDS.UPDATE_TIME = #{updateTime, jdbcType=TIMESTAMP}
and TDS.START_PORT_ID = #{startPortId, jdbcType=BIGINT}
and TDS.START_PORT_NAME = #{startPortName, jdbcType=VARCHAR}
and TDS.END_PORT_ID = #{endPortId, jdbcType=BIGINT}
and TDS.END_PORT_NAME = #{endPortName, jdbcType=VARCHAR}
and TDS.PRE_PORT_ID = #{prePortId, jdbcType=BIGINT}
and TDS.PRE_PORT_NAME = #{prePortName, jdbcType=VARCHAR}
and TDS.NEXT_PORT_ID = #{nextPortId, jdbcType=BIGINT}
and TDS.NEXT_PORT_NAME = #{nextPortName, jdbcType=VARCHAR}
and TDS.SHIP_STATUS_CODE = #{shipStatusCode, jdbcType=VARCHAR}
and TDS.SHIP_STATUS_NAME = #{shipStatusName, jdbcType=VARCHAR}
and ("IN".ID = #{shipVoyage, jdbcType=VARCHAR} OR "OUT".ID = #{shipVoyage, jdbcType=VARCHAR})
AND ("IN".CARGO_CATEGORY_NAME LIKE #{cargoCategoryName,jdbcType=VARCHAR} OR "OUT".CARGO_CATEGORY_NAME LIKE #{cargoCategoryName,jdbcType=VARCHAR})
ORDER BY TDS.CREATE_TIME DESC

SELECT A.START_TIME, A.END_TIME, A.CABIN_NO, A.WORK_LOAD, A.EQUIPMENT_ID, A.EQUIPMENT_NO, A.SHIP_VOYAGE_ID, C.LOAD_UNLOAD, C.CARGO_CATEGORY_NAME "cargoName", A.WORK_LOAD workLoad, ROUND((END_TIME - START_TIME) * 24, 1) AS cnsc, A.REMARK remark FROM T_PRD_DOOR_RECORD A LEFT JOIN T_DIS_SHIPVOYAGE B ON A.SHIP_VOYAGE_ID = B.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM C ON C.ID = A.SHIP_VOYAGE_ITEM_ID
AND A.SHIP_VOYAGE_ID = #{shipvoyageId}
AND C.LOAD_UNLOAD = #{loadUnload}

SELECT TPPSD.CARGO_INFO_ID,
TBCI.CARGO_INFO_NO,
T3.TRUST_NO,
MAX(TPPSD.COMPANY_NAME) COMPANY_NAME,
TO_CHAR( MAX( TPPSD.INOUT_DATE ), 'YYYY-MM-DD' ) INOUT_DATE,
TBCI.TRADE_TYPE TRADE_TYPE,
TBCI.CARGO_OWNER_NAME CARGO_OWNER_NAME,
TBCI.CARGO_AGENT_NAME CARGO_AGENT_NAME,
TBCI.CARGO_NAME CARGO_NAME,
TBCI.PACKING_NAME PACKING_NAME,
SUM(TPPSD.QUANTITY) QUANTITY,
SUM(TPPSD.TON) TON
FROM T_PRD_PORT_STORAGE_DETAIL TPPSD
JOIN T_BUS_CARGO_INFO TBCI ON TPPSD.CARGO_INFO_ID = TBCI.ID
LEFT JOIN (
select
LISTAGG(TRUST_NO, ',') WITHIN GROUP (ORDER BY TRUST_NO) TRUST_NO,CARGO_INFO_ID
FROM (      select TRUST_NO,TBTC.CARGO_INFO_ID
FROM T_BUS_TRUST_CARGO  TBTC
LEFT JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID
GROUP BY TRUST_NO,TBTC.CARGO_INFO_ID
)
GROUP BY  CARGO_INFO_ID
) T3 ON TBCI.ID = T3.CARGO_INFO_ID
LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TBCI.SHIPVOYAGE_ITEM_ID = TDSI.ID



        AND (TPPSD.STOREHOUSE_NAME LIKE #{queryStr_like, jdbcType=VARCHAR}
        OR TPPSD.REGION_NAME LIKE #{queryStr_like, jdbcType=VARCHAR}
        OR TPPSD.MASS_NAME LIKE #{queryStr_like, jdbcType=VARCHAR})


        AND TDSI.SHIPVOYAGE_ID = #{shipVoyageId, jdbcType=BIGINT}


        AND TBCI.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId, jdbcType=BIGINT}



        AND TBCI.SCN LIKE #{scn_like, jdbcType=VARCHAR}


        AND TPPSD.COMPANY_ID = #{companyId, jdbcType=BIGINT}


        AND TBCI.TRADE_TYPE = #{tradeType, jdbcType=VARCHAR}


        AND TPPSD.STOREHOUSE_ID = #{storehouseId, jdbcType=BIGINT}


        AND TPPSD.REGION_ID = #{regionId, jdbcType=BIGINT}


        AND TPPSD.MASS_ID = #{massId, jdbcType=BIGINT}


        AND TBCI.CARGO_OWNER_ID = #{cargoOwnerId, jdbcType=BIGINT}



        AND TBCI.CARGO_NAME LIKE #{cargoNameLike, jdbcType=VARCHAR}


        AND TBCI.PACKING_CODE = #{packingCode, jdbcType=VARCHAR}



        AND TBCI.CARGO_INFO_NO LIKE #{cargoInfoNoLike, jdbcType=VARCHAR}


GROUP BY TPPSD.CARGO_INFO_ID,
TBCI.CARGO_INFO_NO,
T3.TRUST_NO,
TBCI.TRADE_TYPE,
TBCI.CARGO_OWNER_NAME,
TBCI.CARGO_AGENT_NAME,
TBCI.CARGO_NAME,
TBCI.PACKING_NAME

SELECT TPPSD.CARGO_INFO_ID, TPPSD.STOREHOUSE_ID, T3.TRUST_NO, TPPSD.STOREHOUSE_NAME, TPPSD.REGION_ID, TPPSD.REGION_NAME, TPPSD.MASS_ID, TPPSD.MASS_NAME, TBCI.CARGO_INFO_NO, MAX(TPPSD.COMPANY_NAME) COMPANY_NAME, CASE WHEN TBCI.SHIPVOYAGE_ITEM_ID IS NOT NULL THEN TO_CHAR( TBCI.SHIP_NAME ) || '_' || TO_CHAR( TDSI.VOYAGE ) END SHIP_NAME_VOYAGE, TBCI.TRADE_TYPE TRADE_TYPE, TBCI.CARGO_OWNER_NAME CARGO_OWNER_NAME, TBCI.CARGO_AGENT_NAME CARGO_AGENT_NAME, TBCI.CARGO_NAME CARGO_NAME, TO_CHAR( MAX( TPPSD.INOUT_DATE ), 'YYYY-MM-DD' ) INOUT_DATE, TBCI.PACKING_NAME PACKING_NAME, SUM(TPPSD.QUANTITY) QUANTITY, SUM(TPPSD.TON) TON, TO_CHAR( TBCI.COMPANY_NAME ) || '/' || TO_CHAR( TBCI.CARGO_OWNER_NAME ) || '/' || TO_CHAR( TBCI.CARGO_AGENT_NAME ) || '/' || TO_CHAR( TBCI.CARGO_NAME ) || '/' || TO_CHAR( TBCI.TRADE_TYPE ) || '/' || TO_CHAR( TBCI.PACKING_NAME ) CARGO_INFO_LABEL FROM T_PRD_PORT_STORAGE_DETAIL TPPSD JOIN T_BUS_CARGO_INFO TBCI ON TPPSD.CARGO_INFO_ID = TBCI.ID LEFT JOIN ( select LISTAGG(TRUST_NO, ',') WITHIN GROUP (ORDER BY TRUST_NO) TRUST_NO,CARGO_INFO_ID FROM ( select TRUST_NO,TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC LEFT JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID GROUP BY TRUST_NO,TBTC.CARGO_INFO_ID ) GROUP BY CARGO_INFO_ID ) T3 ON TBCI.ID = T3.CARGO_INFO_ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TBCI.SHIPVOYAGE_ITEM_ID = TDSI.ID
AND (TPPSD.STOREHOUSE_NAME LIKE #{queryStr_like, jdbcType=VARCHAR} OR TPPSD.REGION_NAME LIKE #{queryStr_like, jdbcType=VARCHAR} OR TPPSD.MASS_NAME LIKE #{queryStr_like, jdbcType=VARCHAR})
AND TBCI.SCN LIKE #{scn_like, jdbcType=VARCHAR}
AND TPPSD.COMPANY_ID = #{companyId, jdbcType=BIGINT}
AND TBCI.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId, jdbcType=BIGINT}
AND TBCI.TRADE_TYPE = #{tradeType, jdbcType=VARCHAR}
AND TPPSD.STOREHOUSE_ID = #{storehouseId, jdbcType=BIGINT}
AND TPPSD.REGION_ID = #{regionId, jdbcType=BIGINT}
AND TPPSD.MASS_ID = #{massId, jdbcType=BIGINT}
AND TBCI.CARGO_OWNER_ID = #{cargoOwnerId, jdbcType=BIGINT}
AND TBCI.CARGO_NAME LIKE #{cargoNameLike, jdbcType=VARCHAR}
AND TBCI.PACKING_CODE = #{packingCode, jdbcType=VARCHAR}
AND TBCI.CARGO_INFO_NO LIKE #{cargoInfoNoLike, jdbcType=VARCHAR}
GROUP BY TPPSD.CARGO_INFO_ID, T3.TRUST_NO, TPPSD.STOREHOUSE_ID, TPPSD.STOREHOUSE_NAME, TPPSD.REGION_ID, TPPSD.REGION_NAME, TPPSD.MASS_ID, TPPSD.MASS_NAME, TBCI.CARGO_INFO_NO, TBCI.SHIPVOYAGE_ITEM_ID, TBCI.SHIP_NAME, TDSI.VOYAGE, TBCI.TRADE_TYPE, TBCI.CARGO_OWNER_NAME, TBCI.CARGO_AGENT_NAME, TBCI.CARGO_NAME, TBCI.PACKING_NAME, TBCI.COMPANY_NAME

SELECT T1.ID, T1.PORT_STORAGE_ID, T1.CARGO_INFO_ID, T1.WORK_DATE, T1.CLASS_CODE, T1.CLASS_NAME, T1.PROCESS_DETAIL_CODE, T1.PROCESS_DETAIL_NAME, T1.STOREHOUSE_ID, T1.STOREHOUSE_NAME, T1.REGION_ID, T1.REGION_NAME, T1.MASS_ID, T1.MASS_NAME, T1.QUANTITY, T1.TON, T1.INOUT_TYPE, T1.INOUT_STORAGE_CODE, T1.INOUT_STORAGE_NAME, T1.WORK_TICKET_ID, T1.WORK_TICKET_DETAIL_ID, T1.CARGO_TALLY_ID, T1.CARGO_TALLY_DETAIL_ID, T1.INOUT_DATE, T1.CREATE_BY, T1.CREATE_BY_NAME, T1.CREATE_TIME, T1.UPDATE_BY, T1.UPDATE_BY_NAME, T1.UPDATE_TIME, T1.COMPANY_ID, T1.COMPANY_NAME, T1.CLEAN_MASS_SIGN, T2.TRANSPORT_EQUIPMENT_NO, T2.CREATE_BY_NAME AS "TALLY_MAN", T2.CREATE_TIME AS "TALLY_TIME"
FROM T_PRD_PORT_STORAGE_DETAIL T1 LEFT JOIN T_YARD_TALLY T2 ON T1.CARGO_TALLY_ID = T2.ID WHERE T1.CARGO_INFO_ID = #{cargoInfoId,jdbcType=BIGINT} AND T1.STOREHOUSE_ID = #{storehouseId,jdbcType=BIGINT} AND T1.REGION_ID = #{regionId,jdbcType=BIGINT} AND T1.MASS_ID = #{massId,jdbcType=BIGINT}
AND T1.WORK_DATE >= #{beginWorkDate, jdbcType=TIMESTAMP}
AND ( T1.WORK_DATE > #{beginWorkDate, jdbcType=TIMESTAMP} OR T1.CLASS_CODE >= TO_NUMBER( #{beginClassCode, jdbcType=VARCHAR} ) )
AND T1.WORK_DATE <= #{endWorkDate, jdbcType=TIMESTAMP}
AND ( T1.WORK_DATE < #{endWorkDate, jdbcType=TIMESTAMP} OR T1.CLASS_CODE <= TO_NUMBER( #{endClassCode, jdbcType=VARCHAR} ) )
AND T1.PROCESS_DETAIL_CODE = #{processDetailCode, jdbcType=VARCHAR}
ORDER BY T1.WORK_DATE, T1.CLASS_CODE

